// // This register outputs the input data on the falling edge of the clock when the load signal is low.
module register_4bit(
    input clk,
    input ld,
    input [3:0] data,
    output reg [3:0] q
);

    always @(posedge clk) begin
        if (ld)
            q <= data;
    end

endmodule
